/*
 * MIMD Shared Memory System - OpenMP Implementation
 * Demonstrates: Multiple processors with shared address space,
 * independent execution, implicit communication via memory
 */

#include <stdio.h>
#include <stdlib.h>
#include <omp.h>
#include <time.h>

#define ARRAY_SIZE 100
#define NUM_THREADS 4

/* Structure to hold computation results */
typedef struct {
 int processor_id;
 double local_sum;
 double local_max;
 int data_start;
 int data_end;
} ProcessorResult;

/* Parallel computation - each thread executes independently */
void parallel_compute(double *shared_data, double *results, int n) {
 int thread_id = omp_get_thread_num();
 int num_threads = omp_get_num_threads();

 /* Divide work among threads (static scheduling) */
 int chunk_size = n / num_threads;
 int start = thread_id * chunk_size;
 int end = (thread_id == num_threads - 1) ? n : start + chunk_size;

 /* Each processor does independent computation (MIMD: Multiple Instructions) */
 double sum = 0.0;
 double max = shared_data[start];

 /* Different operations based on thread ID (demonstrating MIMD flexibility) */
 if (thread_id % 2 == 0) {
 /* Even threads: compute sum */
 for (int i = start; i < end; i++) {
 sum += shared_data[i];
 }
 results[thread_id] = sum;
 } else {
 /* Odd threads: compute max */
 for (int i = start; i < end; i++) {
 if (shared_data[i] > max) {
 max = shared_data[i];
 }
 }
 results[thread_id] = max;
 }

 printf("Thread %d: processed indices [%d to %d], result = %.2f\n",
 thread_id, start, end - 1, results[thread_id]);
}

/* Demonstrate shared variable vs private variable */
void demonstrate_data_sharing() {
 printf("\n--- Data Sharing Demonstration ---\n");

 int shared_counter = 0; /* Shared among all threads */

 #pragma omp parallel num_threads(4)
 {
 int thread_id = omp_get_thread_num();
 int private_copy = thread_id * 10; /* Private to each thread */

 /* Critical section - only one thread at a time (synchronization) */
 #pragma omp critical
 {
 shared_counter++;
 printf("Thread %d: private=%d, shared_counter=%d\n",
 thread_id, private_copy, shared_counter);
 }
 }

 printf("Final shared_counter = %d\n", shared_counter);
}

/* Parallel section with reduction */
void demonstrate_reduction(double *data, int n) {
 double total_sum = 0.0;
 double total_max = data[0];

 #pragma omp parallel for reduction(+:total_sum) reduction(max:total_max)
 for (int i = 0; i < n; i++) {
 total_sum += data[i];
 if (data[i] > total_max) {
 total_max = data[i];
 }
 }

 printf("\nReduction Results:\n");
 printf(" Total Sum: %.2f\n", total_sum);
 printf(" Maximum: %.2f\n", total_max);
}

int main() {
 printf("========================================\n");
 printf("SHARED MEMORY MIMD SYSTEM - OpenMP\n");
 printf("========================================\n");

 /* Set number of threads */
 omp_set_num_threads(NUM_THREADS);

 /* Initialize shared data */
 double *shared_data = (double*)malloc(ARRAY_SIZE * sizeof(double));
 double *results = (double*)malloc(NUM_THREADS * sizeof(double));

 srand(time(NULL));
 printf("\nInitial Data (first 20 elements):\n");
 for (int i = 0; i < ARRAY_SIZE; i++) {
 shared_data[i] = (rand() % 100) / 10.0;
 if (i < 20) printf("%.1f ", shared_data[i]);
 }
 printf("\n");

 /* Parallel computation using OpenMP */
 printf("\n--- Parallel Computation ---\n");
 double start_time = omp_get_wtime();

 #pragma omp parallel
 {
 parallel_compute(shared_data, results, ARRAY_SIZE);
 }

 double end_time = omp_get_wtime();

 printf("\nExecution time: %.4f seconds\n", end_time - start_time);

 /* Demonstrate data sharing concepts */
 demonstrate_data_sharing();

 /* Demonstrate reduction */
 demonstrate_reduction(shared_data, ARRAY_SIZE);

 printf("\nMIMD Characteristics Demonstrated:\n");
 printf(" - Multiple processors with shared global memory\n");
 printf(" - Independent execution (different operations)\n");
 printf(" - Implicit communication via shared variables\n");
 printf(" - Synchronization via #pragma omp critical\n");

 free(shared_data);
 free(results);

 return 0;
}

/*
 * MIMD Distributed Memory System - MPI Implementation
 * Demonstrates: Multiple processors with local private memory,
 * communication via explicit message passing
 */

#include <stdio.h>
#include <stdlib.h>
#include <mpi.h>
#include <time.h>

#define ARRAY_SIZE 100
#define ROOT_PROCESS 0

/* Structure for local computation results */
typedef struct {
 double local_sum;
 double local_max;
 int data_count;
} LocalResult;

/* Each process performs independent computation on its local data */
LocalResult compute_local(double *local_data, int local_size) {
 LocalResult result;

 result.local_sum = 0.0;
 result.local_max = local_data[0];
 result.data_count = local_size;

 /* Independent computation - each process has its own control flow */
 for (int i = 0; i < local_size; i++) {
 result.local_sum += local_data[i];
 if (local_data[i] > result.local_max) {
 result.local_max = local_data[i];
 }
 }

 return result;
}

/* Demonstrate point-to-point communication */
void demonstrate_point_to_point(int rank, int size) {
 if (rank == 0) {
 int message = 100;
 /* Send to next process */
 MPI_Send(&message, 1, MPI_INT, 1, 0, MPI_COMM_WORLD);
 printf("Process %d: Sent message: %d\n", rank, message);

 /* Receive from last process */
 MPI_Recv(&message, 1, MPI_INT, size - 1, 0, MPI_COMM_WORLD, MPI_STATUS_IGNORE);
 printf("Process %d: Received message: %d\n", rank, message);
 } else if (rank < size - 1) {
 int message;
 /* Receive from previous */
 MPI_Recv(&message, 1, MPI_INT, rank - 1, 0, MPI_COMM_WORLD, MPI_STATUS_IGNORE);
 printf("Process %d: Received: %d, Forwarding...\n", rank, message);

 message++; /* Process modifies data */
 /* Send to next */
 MPI_Send(&message, 1, MPI_INT, rank + 1, 0, MPI_COMM_WORLD);
 printf("Process %d: Sent: %d\n", rank, message);
 } else {
 int message;
 /* Receive from previous */
 MPI_Recv(&message, 1, MPI_INT, rank - 1, 0, MPI_COMM_WORLD, MPI_STATUS_IGNORE);
 printf("Process %d: Received: %d\n", rank, message);

 message++;
 /* Send back to root */
 MPI_Send(&message, 1, MPI_INT, 0, 0, MPI_COMM_WORLD);
 }
}

/* Demonstrate collective communication */
void demonstrate_collective(LocalResult *local_results, int num_procs) {
 double global_sum = 0.0;
 double global_max = 0.0;

 /* Reduce all local sums into global sum */
 MPI_Reduce(&local_results->local_sum, &global_sum, 1, 
 MPI_DOUBLE, MPI_SUM, ROOT_PROCESS, MPI_COMM_WORLD);

 /* Reduce all local maxes into global max */
 MPI_Reduce(&local_results->local_max, &global_max, 1,
 MPI_DOUBLE, MPI_MAX, ROOT_PROCESS, MPI_COMM_WORLD);

 if (local_results->local_sum > -1) { /* Check if this is root */
 int rank;
 MPI_Comm_rank(MPI_COMM_WORLD, &rank);
 if (rank == ROOT_PROCESS) {
 printf("\n--- Collective Communication Results ---\n");
 printf(" Global Sum: %.2f\n", global_sum);
 printf(" Global Max: %.2f\n", global_max);
 }
 }
}

int main(int argc, char *argv[]) {
 int rank, num_procs;

 /* Initialize MPI */
 MPI_Init(&argc, &argv);
 MPI_Comm_rank(MPI_COMM_WORLD, &rank);
 MPI_Comm_size(MPI_COMM_WORLD, &num_procs);

 printf("========================================\n");
 printf("DISTRIBUTED MEMORY MIMD SYSTEM - MPI\n");
 printf("========================================\n");
 printf("Process %d of %d starting...\n", rank, num_procs);

 /* Calculate local data size for each process */
 int local_size = ARRAY_SIZE / num_procs;
 double *local_data = (double*)malloc(local_size * sizeof(double));

 /* Each process generates its own local data (Multiple Data) */
 srand(time(NULL) + rank);
 for (int i = 0; i < local_size; i++) {
 local_data[i] = (rand() % 100) / 10.0;
 }

 printf("Process %d: local data[0..%d] = ", rank, local_size-1);
 for (int i = 0; i < (local_size < 5 ? local_size : 5); i++) {
 printf("%.1f ", local_data[i]);
 }
 printf("\n");

 /* Each process computes independently (Multiple Instructions) */
 LocalResult local_result = compute_local(local_data, local_size);
 printf("Process %d: local_sum = %.2f, local_max = %.2f\n",
 rank, local_result.local_sum, local_result.local_max);

 /* Demonstrate point-to-point communication */
 MPI_Barrier(MPI_COMM_WORLD); /* Synchronize before demo */
 demonstrate_point_to_point(rank, num_procs);

 /* Demonstrate collective communication (reduction) */
 MPI_Barrier(MPI_COMM_WORLD);
 demonstrate_collective(&local_result, num_procs);

 /* Final synchronization */
 MPI_Barrier(MPI_COMM_WORLD);

 if (rank == ROOT_PROCESS) {
 printf("\nMIMD Distributed Memory Characteristics:\n");
 printf(" - Each process has private local memory\n");
 printf(" - Explicit message passing (MPI_Send/MPI_Recv)\n");
 printf(" - Independent execution per process\n");
 printf(" - Communication overhead visible in timing\n");
 }

 free(local_data);
 MPI_Finalize();

 return 0;
}
